    40	    [Fact]
    41	    public async Task Transfer_IsAtomicConservingAndDurablyReplayed()
    42	    {
    43	        var session = await RegisterAsync();
    44	        var sources = await CreateSourcesAsync(session, 5m);
    45	        var request = new RecordWarehouseTransferRequest(sources.Source.Id, sources.Destination.Id, sources.Product.Id, 2m,
    46	            $"transfer-{Guid.NewGuid():N}");
    47	
    48	        using var first = await SendAsync(HttpMethod.Post, "/api/transfers", session.AccessToken, request);
    49	        using var replay = await SendAsync(HttpMethod.Post, "/api/transfers", session.AccessToken, request);
    50	        Assert.Equal(HttpStatusCode.Created, first.StatusCode);
    51	        Assert.Equal(HttpStatusCode.Created, replay.StatusCode);
    52	        var posted = (await first.Content.ReadFromJsonAsync<WarehouseTransferResponse>())!;
    53	        Assert.Equal(posted.Id, (await replay.Content.ReadFromJsonAsync<WarehouseTransferResponse>())!.Id);
    54	
    55	        await using var scope = _fixture.Factory.Services.CreateAsyncScope();
    56	        var db = scope.ServiceProvider.GetRequiredService<ApplicationDbContext>();
