    58	        var movements = await db.InventoryMovements.Where(item => item.Id == transfer.SourceInventoryMovementId ||
    59	            item.Id == transfer.DestinationInventoryMovementId).ToListAsync();
    60	        var balances = await db.InventoryBalances.Where(item => item.WorkspaceId == session.User.Workspace.Id &&
    61	            item.ProductId == sources.Product.Id).ToListAsync();
    62	
    63	        Assert.Equal(2, movements.Count);
    64	        Assert.Contains(movements, item => item.Id == posted.SourceInventoryMovementId && item.Type == InventoryMovementType.Issue && item.Quantity == 2m);
    65	        Assert.Contains(movements, item => item.Id == posted.DestinationInventoryMovementId && item.Type == InventoryMovementType.Receipt && item.Quantity == 2m);
    66	        Assert.Equal(movements[0].OccurredAtUtc, movements[1].OccurredAtUtc);
    67	        Assert.Equal(3m, balances.Single(item => item.WarehouseId == sources.Source.Id).Quantity);
    68	        Assert.Equal(2m, balances.Single(item => item.WarehouseId == sources.Destination.Id).Quantity);
    69	        Assert.Equal(5m, balances.Sum(item => item.Quantity));
    70	        Assert.Single(await db.WarehouseTransfers.Where(item => item.WorkspaceId == session.User.Workspace.Id).ToListAsync());
