    73	    [Fact]
    74	    public async Task OppositeDirectionTransfersUseCompletePairsAndConserveInventory()
    75	    {
    76	        var session = await RegisterAsync();
    77	        var sources = await CreateSourcesAsync(session, 20m);
    78	        var reverseSupplier = await PostAsync<SupplierResponse>("/api/suppliers", session.AccessToken,
