    83	
    84	        var forward = SendAsync(HttpMethod.Post, "/api/transfers", session.AccessToken,
    85	            new RecordWarehouseTransferRequest(sources.Source.Id, sources.Destination.Id, sources.Product.Id, 3m, $"forward-{Guid.NewGuid():N}"));
    86	        var reverse = SendAsync(HttpMethod.Post, "/api/transfers", session.AccessToken,
    87	            new RecordWarehouseTransferRequest(sources.Destination.Id, sources.Source.Id, sources.Product.Id, 4m, $"reverse-{Guid.NewGuid():N}"));
    88	        var responses = await Task.WhenAll(forward, reverse);
    89	        using var first = responses[0];
    90	        using var second = responses[1];
    91	        Assert.Equal(HttpStatusCode.Created, first.StatusCode);
    92	        Assert.Equal(HttpStatusCode.Created, second.StatusCode);
    93	
    94	        await using var scope = _fixture.Factory.Services.CreateAsyncScope();
    95	        var db = scope.ServiceProvider.GetRequiredService<ApplicationDbContext>();
    96	        var transfers = await db.WarehouseTransfers.Where(item => item.WorkspaceId == session.User.Workspace.Id).ToListAsync();
    97	        var balances = await db.InventoryBalances.Where(item => item.WorkspaceId == session.User.Workspace.Id &&
    98	            item.ProductId == sources.Product.Id).ToListAsync();
    99	        Assert.Equal(2, transfers.Count);
   100	        Assert.Equal(6, await db.InventoryMovements.CountAsync(item => item.WorkspaceId == session.User.Workspace.Id));
   101	        Assert.Equal(40m, balances.Sum(item => item.Quantity));
