   109	        var sources = await CreateSourcesAsync(session, 1m);
   110	        using var response = await SendAsync(HttpMethod.Post, "/api/transfers", session.AccessToken,
   111	            new RecordWarehouseTransferRequest(sources.Source.Id, sources.Destination.Id, sources.Product.Id, 1.0001m,
   112	                $"overdraft-{Guid.NewGuid():N}"));
   113	        Assert.Equal(HttpStatusCode.Conflict, response.StatusCode);
   114	
   115	        await using var scope = _fixture.Factory.Services.CreateAsyncScope();
   116	        var db = scope.ServiceProvider.GetRequiredService<ApplicationDbContext>();
   117	        Assert.Empty(await db.WarehouseTransfers.Where(item => item.WorkspaceId == session.User.Workspace.Id).ToListAsync());
   118	        Assert.Empty(await db.InventoryBalances.Where(item => item.WorkspaceId == session.User.Workspace.Id &&
   119	            item.WarehouseId == sources.Destination.Id && item.ProductId == sources.Product.Id).ToListAsync());
   120	        Assert.Equal(1m, await db.InventoryBalances.Where(item => item.WorkspaceId == session.User.Workspace.Id &&
   121	            item.WarehouseId == sources.Source.Id && item.ProductId == sources.Product.Id).Select(item => item.Quantity).SingleAsync());
   122	    }
