   124	    private async Task<Sources> CreateSourcesAsync(AuthenticationResponse session, decimal quantity)
   125	    {
   126	        var suffix = Guid.NewGuid().ToString("N");
   127	        var supplier = await PostAsync<SupplierResponse>("/api/suppliers", session.AccessToken, new CreateSupplierRequest($"Supplier {suffix}"));
   128	        var source = await PostAsync<WarehouseResponse>("/api/warehouses", session.AccessToken, new CreateWarehouseRequest($"Source {suffix}"));
   129	        var destination = await PostAsync<WarehouseResponse>("/api/warehouses", session.AccessToken, new CreateWarehouseRequest($"Destination {suffix}"));
   130	        var product = await PostAsync<ProductResponse>("/api/products", session.AccessToken, new CreateProductRequest($"Product {suffix}", $"SKU-{suffix}"));
   131	        await PostAsync<PurchaseReceiptResponse>("/api/purchases/receipts", session.AccessToken,
   132	            new RecordPurchaseReceiptRequest(supplier.Id, source.Id, product.Id, quantity, $"receipt-{suffix}"));
   133	        return new Sources(source, destination, product);
   134	    }
   135	
   136	    private async Task<T> PostAsync<T>(string path, string token, object content)
   137	    {
   138	        using var response = await SendAsync(HttpMethod.Post, path, token, content);
   139	        Assert.Equal(HttpStatusCode.Created, response.StatusCode);
   140	        return (await response.Content.ReadFromJsonAsync<T>())!;
   141	    }
   142	
   143	    private async Task<AuthenticationResponse> RegisterAsync()
   144	    {
   145	        var suffix = Guid.NewGuid().ToString("N");
   146	        using var response = await _client.PostAsJsonAsync("/api/auth/register", new RegisterUserCommand($"User {suffix}",
   147	            $"user-{suffix}@example.test", "Password!12345"));
   148	        Assert.Equal(HttpStatusCode.OK, response.StatusCode);
   149	        return (await response.Content.ReadFromJsonAsync<AuthenticationResponse>())!;
   150	    }
   151	
   152	    private async Task<HttpResponseMessage> SendAsync(HttpMethod method, string path, string token, object? content = null)
   153	    {
   154	        using var request = new HttpRequestMessage(method, path);
   155	        request.Headers.Authorization = new AuthenticationHeaderValue("Bearer", token);
   156	        if (content is not null) request.Content = JsonContent.Create(content);
   157	        return await _client.SendAsync(request);
   158	    }
   159	
   160	    private sealed record Sources(WarehouseResponse Source, WarehouseResponse Destination, ProductResponse Product);
   161	}

