     7	namespace InventoryFlow.Api.Controllers;
     8	
     9	[ApiController]
    10	[Authorize]
    11	[Route("api/transfers")]
    12	public sealed class WarehouseTransfersController(ISender sender, ICurrentWorkspace currentWorkspace) : ControllerBase
    13	{
    14	    [HttpPost]
    15	    [ProducesResponseType<WarehouseTransferResponse>(StatusCodes.Status201Created)]
    16	    [ProducesResponseType(StatusCodes.Status403Forbidden)]
    17	    [ProducesResponseType(StatusCodes.Status404NotFound)]
    18	    public async Task<ActionResult<WarehouseTransferResponse>> Record(RecordWarehouseTransferRequest request,
    19	        [FromHeader(Name = "Idempotency-Key")] string? idempotencyKey, CancellationToken cancellationToken)
    20	    {
    21	        var workspace = await currentWorkspace.GetAsync(cancellationToken);
    22	        if (workspace is null) return Forbid();
    23	        var transfer = await sender.Send(new RecordWarehouseTransferCommand(workspace.Id, request.SourceWarehouseId,
    24	            request.DestinationWarehouseId, request.ProductId, request.Quantity, idempotencyKey ?? request.IdempotencyKey), cancellationToken);
