     9	    public void Configure(EntityTypeBuilder<WarehouseTransfer> builder)
    10	    {
    11	        builder.ToTable("WarehouseTransfers");
    12	        builder.HasKey(transfer => transfer.Id);
    13	        builder.Property(transfer => transfer.Quantity).HasPrecision(18, 4).IsRequired();
    14	        builder.Property(transfer => transfer.IdempotencyKey).HasMaxLength(InventoryMovement.IdempotencyKeyMaxLength).IsRequired();
    15	        builder.Property(transfer => transfer.TransferredAtUtc).IsRequired();
    16	        builder.HasIndex(transfer => new { transfer.WorkspaceId, transfer.IdempotencyKey }).IsUnique();
    17	        builder.HasIndex(transfer => transfer.SourceInventoryMovementId).IsUnique();
    18	        builder.HasIndex(transfer => transfer.DestinationInventoryMovementId).IsUnique();
    19	        builder.HasIndex(transfer => new { transfer.WorkspaceId, transfer.TransferredAtUtc, transfer.Id });
    20	        builder.HasOne<Workspace>().WithMany().HasForeignKey(transfer => transfer.WorkspaceId).OnDelete(DeleteBehavior.Cascade);
    21	        builder.HasOne<Warehouse>().WithMany().HasForeignKey(transfer => transfer.SourceWarehouseId).OnDelete(DeleteBehavior.Restrict);
    22	        builder.HasOne<Warehouse>().WithMany().HasForeignKey(transfer => transfer.DestinationWarehouseId).OnDelete(DeleteBehavior.Restrict);
    23	        builder.HasOne<Product>().WithMany().HasForeignKey(transfer => transfer.ProductId).OnDelete(DeleteBehavior.Restrict);
    24	        builder.HasOne<InventoryMovement>().WithMany().HasForeignKey(transfer => transfer.SourceInventoryMovementId).OnDelete(DeleteBehavior.Restrict);
    25	        builder.HasOne<InventoryMovement>().WithMany().HasForeignKey(transfer => transfer.DestinationInventoryMovementId).OnDelete(DeleteBehavior.Restrict);
