     1	using InventoryFlow.Domain.Common;
     2	using InventoryFlow.Domain.Exceptions;
     3	
     4	namespace InventoryFlow.Domain.Entities;
     5	
     6	/// <summary>An immutable posted single-product transfer between two warehouses.</summary>
     7	public sealed class WarehouseTransfer : Entity<Guid>
     8	{
     9	    public WarehouseTransfer(Guid id, Guid workspaceId, Guid sourceWarehouseId, Guid destinationWarehouseId, Guid productId,
    10	        decimal quantity, string idempotencyKey, Guid sourceInventoryMovementId, Guid destinationInventoryMovementId,
    11	        DateTimeOffset transferredAtUtc) : base(id)
    12	    {
    13	        if (id == Guid.Empty || workspaceId == Guid.Empty || sourceWarehouseId == Guid.Empty || destinationWarehouseId == Guid.Empty ||
    14	            productId == Guid.Empty || sourceInventoryMovementId == Guid.Empty || destinationInventoryMovementId == Guid.Empty)
    15	            throw new DomainException("Warehouse transfer identifiers are required.");
    16	        if (sourceWarehouseId == destinationWarehouseId)
    17	            throw new DomainException("Source and destination warehouses must be different.");
    18	        if (sourceInventoryMovementId == destinationInventoryMovementId)
    19	            throw new DomainException("Warehouse transfer movements must be different.");
    20	        if (transferredAtUtc.Offset != TimeSpan.Zero)
    21	            throw new DomainException("Warehouse transfer time must be in UTC.");
    22	
    23	        WorkspaceId = workspaceId;
    24	        SourceWarehouseId = sourceWarehouseId;
    25	        DestinationWarehouseId = destinationWarehouseId;
    26	        ProductId = productId;
    27	        Quantity = InventoryMovement.ValidateQuantity(quantity);
    28	        IdempotencyKey = InventoryMovement.NormalizeIdempotencyKey(idempotencyKey);
    29	        SourceInventoryMovementId = sourceInventoryMovementId;
    30	        DestinationInventoryMovementId = destinationInventoryMovementId;
    31	        TransferredAtUtc = transferredAtUtc;
    32	    }
    33	
    34	    public Guid WorkspaceId { get; private set; }
    35	    public Guid SourceWarehouseId { get; private set; }
    36	    public Guid DestinationWarehouseId { get; private set; }
    37	    public Guid ProductId { get; private set; }
    38	    public decimal Quantity { get; private set; }
    39	    public string IdempotencyKey { get; private set; }
    40	    public Guid SourceInventoryMovementId { get; private set; }
    41	    public Guid DestinationInventoryMovementId { get; private set; }
    42	    public DateTimeOffset TransferredAtUtc { get; private set; }
    43	}
