    36	public static class InfrastructureServiceCollectionExtensions
    37	{
    38	    /// <summary>
    39	    /// Adds SQL Server persistence and ASP.NET Core Identity services.
    40	    /// </summary>
    41	    /// <param name="services">The dependency-injection service collection.</param>
    42	    /// <param name="configuration">The application configuration.</param>
    43	    /// <returns>The supplied <paramref name="services"/> instance.</returns>
    44	    /// <exception cref="ArgumentException">Thrown when the database connection string is missing.</exception>
    45	    public static IServiceCollection AddInfrastructure(
    46	        this IServiceCollection services,
    47	        IConfiguration configuration)
    48	    {
    49	        ArgumentNullException.ThrowIfNull(services);
    50	        ArgumentNullException.ThrowIfNull(configuration);
    51	
    52	        var connectionString = configuration.GetConnectionString("InventoryFlowDatabase");
    53	        ArgumentException.ThrowIfNullOrWhiteSpace(
    54	            connectionString,
    55	            "ConnectionStrings:InventoryFlowDatabase");
    56	
    57	        services.AddOptions<JwtOptions>()
    58	            .Bind(configuration.GetSection(JwtOptions.SectionName))
    59	            .ValidateDataAnnotations()
    60	            .Validate(options => Encoding.UTF8.GetByteCount(options.SigningKey) >= 32, "Jwt signing key must be at least 32 bytes.")
    61	            .ValidateOnStart();
    62	        var jwt = configuration.GetSection(JwtOptions.SectionName).Get<JwtOptions>() ?? new JwtOptions();
    63	
    64	        services.AddAuthentication(JwtBearerDefaults.AuthenticationScheme)
    65	            .AddJwtBearer(options =>
    66	            {
    67	                options.TokenValidationParameters = new TokenValidationParameters
    68	                {
    69	                    ValidateIssuer = true,
    70	                    ValidIssuer = jwt.Issuer,
    71	                    ValidateAudience = true,
    72	                    ValidAudience = jwt.Audience,
    73	                    ValidateIssuerSigningKey = true,
    74	                    IssuerSigningKey = new SymmetricSecurityKey(Encoding.UTF8.GetBytes(jwt.SigningKey)),
    75	                    ValidateLifetime = true,
    76	                    ClockSkew = TimeSpan.Zero,
    77	                    NameClaimType = "display_name"
    78	                };
    79	            });
    80	        services.AddHttpContextAccessor();
    81	        services.AddSingleton(TimeProvider.System);
    82	        services.AddScoped<ICurrentWorkspace, CurrentWorkspaceResolver>();
    83	        services.AddScoped<JwtAccessTokenIssuer>();
    84	        services.AddSingleton<RefreshTokenGenerator>();
    85	        services.AddScoped<IAuthenticationService, IdentityAuthenticationService>();
    86	        services.AddScoped<IProductCatalog, EfProductCatalog>();
    87	        services.AddScoped<IWarehouseCatalog, EfWarehouseCatalog>();
    88	        services.AddScoped<ISupplierCatalog, EfSupplierCatalog>();
    89	        services.AddScoped<IInventoryLedger, EfInventoryLedger>();
    90	        services.AddScoped<IPurchaseReceiptService, EfPurchaseReceiptService>();
    91	        services.AddScoped<ISalesFulfillmentService, EfSalesFulfillmentService>();
    92	        services.AddScoped<IWarehouseTransferService, EfWarehouseTransferService>();
    93	
    94	        services.AddDbContext<ApplicationDbContext>(options => options.UseSqlServer(
    95	            connectionString,
    96	            sqlServerOptions => sqlServerOptions.EnableRetryOnFailure()));
    97	        services.AddDataProtection()
    98	            .SetApplicationName("InventoryFlow")
    99	            .PersistKeysToDbContext<ApplicationDbContext>();
   100	
   101	        services.AddIdentityCore<ApplicationUser>(options =>
   102	            {
   103	                options.User.RequireUniqueEmail = true;
   104	                options.Password.RequiredLength = 12;
   105	                options.Password.RequireDigit = true;
   106	                options.Password.RequireLowercase = true;
   107	                options.Password.RequireUppercase = true;
   108	                options.Password.RequireNonAlphanumeric = true;
   109	                options.Lockout.AllowedForNewUsers = true;
   110	                options.Lockout.DefaultLockoutTimeSpan = TimeSpan.FromMinutes(15);
   111	                options.Lockout.MaxFailedAccessAttempts = 5;
   112	            })
   113	            .AddRoles<IdentityRole<Guid>>()
   114	            .AddEntityFrameworkStores<ApplicationDbContext>()
   115	            .AddSignInManager()
   116	            .AddDefaultTokenProviders();
   117	
   118	        return services;
   119	    }
   120	}
