    10	/// <summary>Posts immutable purchase receipts and their ledger entries in one transaction.</summary>
    11	public sealed class EfPurchaseReceiptService(ApplicationDbContext dbContext) : IPurchaseReceiptService
    12	{
    13	    public async Task<PurchaseReceipt?> RecordAsync(Guid workspaceId, Guid supplierId, Guid warehouseId, Guid productId, decimal quantity,
    14	        string idempotencyKey, DateTimeOffset receivedAtUtc, CancellationToken cancellationToken)
    15	    {
    16	        quantity = InventoryMovement.ValidateQuantity(quantity);
    17	        idempotencyKey = InventoryMovement.NormalizeIdempotencyKey(idempotencyKey);
    18	        var strategy = dbContext.Database.CreateExecutionStrategy();
    19	        return await strategy.ExecuteAsync(async () =>
    20	        {
    21	            await using var transaction = await dbContext.Database.BeginTransactionAsync(IsolationLevel.Serializable, cancellationToken);
    22	            var existing = await dbContext.PurchaseReceipts.SingleOrDefaultAsync(receipt => receipt.WorkspaceId == workspaceId &&
    23	                receipt.IdempotencyKey == idempotencyKey, cancellationToken);
    24	            if (existing is not null)
    25	            {
    26	                await transaction.CommitAsync(cancellationToken);
    27	                return existing;
    28	            }
    29	
    30	            var supplierExists = await dbContext.Suppliers.AnyAsync(supplier => supplier.Id == supplierId &&
    31	                supplier.WorkspaceId == workspaceId && supplier.ArchivedAtUtc == null, cancellationToken);
    32	            if (!supplierExists)
    33	            {
    34	                await transaction.RollbackAsync(cancellationToken);
    35	                return null;
    36	            }
    37	
    38	            var receiptId = Guid.NewGuid();
    39	            var movement = await new InventoryLedgerWriter(dbContext).RecordAsync(workspaceId, warehouseId, productId,
    40	                InventoryMovementType.Receipt, quantity, receiptId.ToString("N"), receivedAtUtc, Guid.NewGuid(), cancellationToken);
    41	            if (movement is null)
    42	            {
    43	                await transaction.RollbackAsync(cancellationToken);
    44	                return null;
    45	            }
    46	
    47	            var receipt = new PurchaseReceipt(receiptId, workspaceId, supplierId, warehouseId, productId, quantity, idempotencyKey,
    48	                movement.Id, receivedAtUtc);
    49	            dbContext.PurchaseReceipts.Add(receipt);
    50	            await dbContext.SaveChangesAsync(cancellationToken);
    51	            await transaction.CommitAsync(cancellationToken);
    52	            return receipt;
    53	        });
    54	    }
    55	
    56	    public async Task<IReadOnlyList<PurchaseReceipt>> ListAsync(Guid workspaceId, CancellationToken cancellationToken) =>
    57	        await dbContext.PurchaseReceipts.AsNoTracking().Where(receipt => receipt.WorkspaceId == workspaceId)
    58	            .OrderByDescending(receipt => receipt.ReceivedAtUtc).ThenByDescending(receipt => receipt.Id).ToListAsync(cancellationToken);
    59	}
